SELECT AVG(tests.test_cost) AS average_cost
FROM tests
WHERE tests.test_duration > 30 AND tests.test_type = 'Urine';

SELECT COUNT(*) AS total_tests, test_type 
FROM tests 
GROUP BY test_type;

SELECT COUNT(DISTINCT test_id) AS unique_blood_test_count
FROM tests
WHERE test_type = 'Blood' AND test_cost <= 100;

SELECT test_name
FROM tests
WHERE test_id = 1;

SELECT test_name, test_type, test_cost, test_duration, description
FROM tests
ORDER BY test_cost DESC;
